**Regression test for auth grace window boundary:**

```javascript
describe('auth grace window', () => {
  it('accepts token within 30s grace window', () => {
    const token = createExpiredToken(-30); // 30s ago
    const req = mockRequest({ headers: { authorization: `Bearer ${token}` }});

    authMiddleware(req, res, (err) => {
      expect(err).toBeUndefined();
      expect(req.session.userId).toBeDefined();
    });
  });

  it('rejects token beyond 30s grace window', () => {
    const token = createExpiredToken(-31); // 31s ago  
    const req = mockRequest({ headers: { authorization: `Bearer ${token}` }});

    authMiddleware(req, res, (err) => {
      expect(err.status).toBe(401);
      expect(req.session).toBeUndefined();
    });
  });
});
```

