**Target:** Convert callback to async/await while preserving execution order and error handling.

**Minimal conversion pattern:**
```javascript
// Before
function handler(req, res, next) {
  validateInputs(req, (err) => {
    if (err) return next(err);
    db.findUser(req.session.userId, (err, user) => {
      if (err) return next(err);
      if (!user) return next(new Error('User not found'));
      performSideEffect(user, (err, result) => {
        if (err) return next(err);
        res.json(result);
      });
    });
  });
}

